// secure-web3-service.js
const { ethers } = require('ethers');
require('dotenv').config();

class SecureWeb3Service {
  constructor() {
    // Use environment variables - NEVER hardcode private keys
    this.provider = new ethers.JsonRpcProvider(process.env.RPC_URL);
    
    // Load wallet from encrypted keystore or environment variable
    this.wallet = null;
    this.initializeWallet();
  }

  async initializeWallet() {
    // Option 1: Use encrypted keystore (RECOMMENDED)
    if (process.env.KEYSTORE_PATH && process.env.KEYSTORE_PASSWORD) {
      const keystoreJson = require('fs').readFileSync(process.env.KEYSTORE_PATH, 'utf8');
      this.wallet = await ethers.Wallet.fromEncryptedJson(
        keystoreJson,
        process.env.KEYSTORE_PASSWORD
      );
    }
    // Option 2: Environment variable (for development only)
    else if (process.env.PRIVATE_KEY) {
      this.wallet = new ethers.Wallet(process.env.PRIVATE_KEY);
    }
    // Option 3: Use AWS KMS, HashiCorp Vault, or other secret management
    else {
      throw new Error('No secure wallet configuration found');
    }
    
    this.wallet = this.wallet.connect(this.provider);
  }

  async sendETH(toAddress, amountInEther) {
    try {
      const tx = await this.wallet.sendTransaction({
        to: toAddress,
        value: ethers.parseEther(amountInEther.toString())
      });
      
      const receipt = await tx.wait();
      return {
        success: true,
        txHash: receipt.hash,
        blockNumber: receipt.blockNumber
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async interactWithContract(contractAddress, abi, functionName, params = [], value = '0') {
    try {
      const contract = new ethers.Contract(contractAddress, abi, this.wallet);
      
      const tx = await contract[functionName](...params, {
        value: ethers.parseEther(value.toString())
      });
      
      const receipt = await tx.wait();
      return {
        success: true,
        txHash: receipt.hash,
        blockNumber: receipt.blockNumber
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async readContract(contractAddress, abi, functionName, params = []) {
    try {
      const contract = new ethers.Contract(contractAddress, abi, this.provider);
      const result = await contract[functionName](...params);
      return {
        success: true,
        data: result
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async getBalance(address) {
    const balance = await this.provider.getBalance(address);
    return ethers.formatEther(balance);
  }

  getAddress() {
    return this.wallet.address;
  }
}

module.exports = SecureWeb3Service;